sql:
SELECT COUNT(installation_id)
FROM installations
WHERE app_id = 0;

SELECT device_id, COUNT(user_id) AS total_users
FROM user_demographics
GROUP BY device_id;

SELECT AVG(age) 
FROM user_demographics 
WHERE app_id = 0;

SELECT app_id, date, SUM(active_users) AS total_active_users
FROM daily_active_users
GROUP BY app_id, date;

SELECT app_id, SUM(installation_count) AS total_installations
FROM installations
GROUP BY app_id;

SELECT AVG(installation_count) AS average_installation_count
FROM installations
WHERE app_id = 1 AND date = '2015-01-01';

SELECT user_id
FROM user_behavior
WHERE action = 'Purchase';

SELECT date, active_users
FROM daily_active_users
WHERE app_id = 1 AND os_id = 1;

SELECT AVG(total_installations) AS average_installations
FROM (
    SELECT SUM(installation_count) AS total_installations
    FROM installations
    GROUP BY country_id
);

SELECT COUNT(*)
FROM retention_rates
WHERE (day_1 + day_3 + day_7 + day_14 + day_30 + day_60 + day_90 + day_120 + day_150 + day_180) > 50;

SELECT ud.user_id, ud.age, ud.gender, ub.action, ub.timestamp
FROM user_demographics ud
JOIN user_behavior ub ON ud.user_id = ub.user_id;

SELECT date, active_users, app_id
FROM daily_active_users
ORDER BY active_users DESC;

SELECT user_id, COUNT(action) AS total_actions
FROM user_behavior
GROUP BY user_id;
